import heapq
class Solution:
    def maxTotal(self, value, limit):
        groups = {}
        for v, l in zip(value, limit):
            groups.setdefault(l, []).append(v)
        total = 0
        for l, vs in groups.items():
            for v in heapq.nlargest(l, vs):
                total += v
        return total

