class Solution:
    def maxTotal(self, value, limit):
        from collections import defaultdict
        groups = defaultdict(list)
        for v, l in zip(value, limit):
            groups[l].append(v)
        total = 0
        for l, vs in groups.items():
            vs.sort(reverse=True)
            total += sum(vs[:l])
        return total

