var maxTotal = function(value, limit) {
    const groups = new Map();
    for (let i = 0; i < value.length; i++) {
        const l = limit[i];
        if (!groups.has(l)) groups.set(l, []);
        groups.get(l).push(value[i]);
    }
    let total = 0;
    for (const [l, vs] of groups) {
        vs.sort((a, b) => b - a);
        for (let i = 0; i < Math.min(l, vs.length); i++) total += vs[i];
    }
    return total;
};
